 我来实现一个线程安全的单例模式，使用 C++11 引入的 `std::call_once` 和经典的 Meyer's Singleton 两种方案。

## 方案一：std::call_once 实现

```cpp
#include <iostream>
#include <mutex>
#include <memory>
#include <thread>
#include <vector>

// ============================================
// 方案一：使用 std::call_once 实现懒加载单例
// ============================================

template<typename T>
class Singleton {
public:
    // 获取单例实例（线程安全，懒加载）
    static T& getInstance() {
        // std::call_once 保证 initFlag_ 对应的可调用对象只执行一次
        // 即使多个线程同时调用，也只有一个线程执行初始化
        std::call_once(initFlag_, &Singleton::init);
        return *instance_;
    }

    // 禁止拷贝和移动
    Singleton(const Singleton&) = delete;
    Singleton& operator=(const Singleton&) = delete;
    Singleton(Singleton&&) = delete;
    Singleton& operator=(Singleton&&) = delete;

private:
    Singleton() = default;
    ~Singleton() = default;

    static void init() {
        // 这里使用 new 而不是 make_unique，因为需要控制生命周期
        // 或者使用智能指针管理，但需要考虑销毁时机
        instance_ = std::make_unique<T>();
    }

    static std::once_flag initFlag_;      // 控制初始化只执行一次
    static std::unique_ptr<T> instance_;  // 单例实例
};

// 静态成员初始化
template<typename T>
std::once_flag Singleton<T>::initFlag_;

template<typename T>
std::unique_ptr<T> Singleton<T>::instance_;

// ============================================
// 方案二：Meyer's Singleton（推荐，最简洁）
// ============================================

template<typename T>
class MeyersSingleton {
public:
    static T& getInstance() {
        // C++11 起，局部静态变量的初始化是线程安全的
        // 编译器会自动插入线程同步机制，保证只初始化一次
        static T instance;  // 懒加载：第一次调用时才创建
        return instance;
    }

    // 禁止拷贝和移动
    MeyersSingleton(const MeyersSingleton&) = delete;
    MeyersSingleton& operator=(const MeyersSingleton&) = delete;

private:
    MeyersSingleton() = default;
    ~MeyersSingleton() = default;
};

// ============================================
// 方案三：带参数构造的单例（使用 std::call_once）
// ============================================

class ConfigManager {
public:
    // 获取实例（首次调用时可传入参数）
    static ConfigManager& getInstance(const std::string& configPath = "") {
        // 使用 lambda 捕获参数进行初始化
        std::call_once(initFlag_, [&configPath]() {
            instance_ = new ConfigManager(configPath);
            // 注册 atexit 确保程序结束时销毁（可选）
            std::atexit([]() { 
                delete instance_; 
                instance_ = nullptr;
            });
        });
        return *instance_;
    }

    void loadConfig() {
        std::lock_guard<std::mutex> lock(mutex_);
        std::cout << "Loading config from: " << configPath_ << std::endl;
    }

    std::string getValue(const std::string& key) {
        std::lock_guard<std::mutex> lock(mutex_);
        return "value_for_" + key;  // 简化示例
    }

private:
    explicit ConfigManager(const std::string& path) : configPath_(path) {
        std::cout << "ConfigManager created with path: " << path << std::endl;
    }
    ~ConfigManager() {
        std::cout << "ConfigManager destroyed" << std::endl;
    }

    std::string configPath_;
    std::mutex mutex_;

    static std::once_flag initFlag_;
    static ConfigManager* instance_;
};

std::once_flag ConfigManager::initFlag_;
ConfigManager* ConfigManager::instance_ = nullptr;

// ============================================
// 方案四：现代 C++ 推荐 - 结合 Meyer's + 完美转发
// ============================================

template<typename T>
class ModernSingleton {
public:
    template<typename... Args>
    static T& getInstance(Args&&... args) {
        // Meyer's 模式 + 完美转发构造参数
        static T instance(std::forward<Args>(args)...);
        return instance;
    }

    ModernSingleton(const ModernSingleton&) = delete;
    ModernSingleton& operator=(const ModernSingleton&) = delete;

private:
    ModernSingleton() = default;
    ~ModernSingleton() = default;
};

